 Iterator it = identities.iterator();
 
 StringBuilder returnString = new StringBuilder();
 
 while ((null != it) && (it.hasNext())) {

   //Identity identity = it.next();
   
   identityName = it.next();
   
   Identity identity = context.getObjectByName(Identity.class, identityName);

   //Date currentDate = new Date();
   ctrexpDate = "2025-02-12"; //Change this Date, CWRs will get extended to this date
   
   if (identity != null){  
	   identity.setAttribute("ctrexpDt",ctrexpDate);
		context.saveObject(identity);
   
		context.commitTransaction();
		returnString.append(identity.getName()).append(" | ").append(identity.getAttribute("samAccountName")).append("\n");
	}      
}

return returnString.toString();
